def compute_score():
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    slide = None
    for s in prs.slides:
        if hasattr(s, 'slide_id') and s.slide_id == '13':
            slide = s
            break
    if not slide:
        try:
            slide = list(prs.slides)[12]
        except IndexError:
            return 'Slide 13 not found in modified PPT.', 0.0
    chart_count = 0
    for shape in slide.shapes:
        if shape.shape_type == 3:  # CHART
            chart_count += 1
    if chart_count == 0:
        return 'No chart found on slide 13.', 0.0
    return f'Found {chart_count} chart(s) on slide 13.', 1.0

def compute_score():
    def use_vlm_fallback():
        """Use vision-language model to verify chart-table correspondence"""
        try:
            # Get screenshot of slide 13
            slide_image = modified_ppt_screenshots[12].image_path

            prompt = """
            Analyze this PowerPoint slide that contains both a table and a chart.

            Task: Determine if the chart accurately represents the data shown in the table.

            Please check:
            1. Do the category labels in the chart match the categories in the table?
            2. Do the values/proportions in the chart correspond to the numeric data in the table?
            3. Is the chart type appropriate for representing this table data?

            Respond with:
            - "MATCH" if the chart accurately represents the table data
            - "PARTIAL_MATCH" if there are minor discrepancies but the chart generally represents the table
            - "NO_MATCH" if the chart does not represent the table data accurately

            Also provide a brief explanation of your assessment.
            """

            response = vlm_call(prompt, [slide_image])

            if "MATCH" in response and "NO_MATCH" not in response:
                if "PARTIAL_MATCH" in response:
                    return response, 0.7
                else:
                    return response, 1.0
            elif "PARTIAL_MATCH" in response:
                return response, 0.6
            else:
                return response, 0.0

        except Exception as e:
            return f"Error in VLM fallback: {e}", 0.0


    from pptx import Presentation
    from pptx.enum.shapes import MSO_SHAPE_TYPE
    import difflib

    try:
        prs = Presentation(modified_ppt_path)

        # Get slide 13 (index 12)
        if len(prs.slides) < 13:
            return 'Slide 13 not found in modified PPT.', 0.0

        slide = prs.slides[12]  # 0-based indexing

        # Find chart and table on slide 13
        chart_shape = None
        table_shape = None

        for shape in slide.shapes:
            if shape.shape_type == MSO_SHAPE_TYPE.CHART:
                chart_shape = shape
            elif shape.shape_type == MSO_SHAPE_TYPE.TABLE:
                table_shape = shape

        if not chart_shape:
            return 'No chart present on slide 13.', 0.0

        if not table_shape:
            return 'No table found on slide 13 to extract data.', 0.0

        # Extract table data
        table = table_shape.table
        table_data = []

        for row_idx in range(len(table.rows)):
            row = []
            for cell in table.rows[row_idx].cells:
                row.append(cell.text.strip())
            table_data.append(row)

        if len(table_data) < 2:
            return 'Table has insufficient data (less than 2 rows).', 0.0

        # Extract chart data more robustly
        try:
            chart = chart_shape.chart
            chart_data = None
            chart_categories = None

            # Try to get data from chart plots
            if chart.plots and len(chart.plots) > 0:
                plot = chart.plots[0]
                if plot.series and len(plot.series) > 0:
                    series = plot.series[0]

                    # Get values
                    if hasattr(series, 'values') and series.values:
                        chart_data = [float(v) if v is not None else 0.0 for v in series.values]

                    # Get categories 
                    if hasattr(plot, 'categories') and plot.categories:
                        chart_categories = [str(c) for c in plot.categories]
                    elif hasattr(series, 'categories') and series.categories:
                        chart_categories = [str(c) for c in series.categories]

            if not chart_data:
                return use_vlm_fallback()

        except Exception as e:
            return use_vlm_fallback()

        # Parse table data (assume first row is header)
        headers = table_data[0]
        data_rows = table_data[1:]

        # Extract categories and values from table
        table_categories = []
        table_values = []

        for row in data_rows:
            if len(row) >= 2:
                category = row[0].strip()
                try:
                    # Try to parse the value (could be in different columns)
                    value = None
                    for cell in row[1:]:
                        try:
                            # Remove any non-numeric characters except decimal point
                            clean_cell = ''.join(c for c in cell if c.isdigit() or c == '.')
                            if clean_cell:
                                value = float(clean_cell)
                                break
                        except ValueError:
                            continue

                    if value is not None and category:
                        table_categories.append(category)
                        table_values.append(value)

                except (ValueError, IndexError):
                    continue

        if not table_values or not table_categories:
            return use_vlm_fallback()


        # Category matching (fuzzy)
        matched_categories = 0
        if chart_categories:
            for table_cat in table_categories:
                for chart_cat in chart_categories:
                    # Check for substring match (case insensitive)
                    if (table_cat.lower() in chart_cat.lower() or 
                        chart_cat.lower() in table_cat.lower() or
                        difflib.SequenceMatcher(None, table_cat.lower(), chart_cat.lower()).ratio() > 0.7):
                        matched_categories += 1
                        break

        category_score = matched_categories / max(len(table_categories), 1) if table_categories else 0

        # Value matching
        value_score = 0
        if len(table_values) == len(chart_data):
            # Check if values match within tolerance
            total_diff = 0
            total_magnitude = sum(abs(v) for v in table_values)

            for tv, cv in zip(table_values, chart_data):
                total_diff += abs(tv - cv)

            if total_magnitude > 0:
                relative_error = total_diff / total_magnitude
                value_score = max(0, 1 - relative_error)
            else:
                value_score = 1 if total_diff == 0 else 0

        # Overall score (weight categories and values equally)
        overall_score = 0.5 * category_score + 0.5 * value_score


        if overall_score > 0.9:
            return 'Chart data accurately matches table data.', 1.0
        elif overall_score > 0.7:
            return 'Chart data closely matches table data.', 0.8
        elif overall_score > 0.5:
            return 'Chart partially matches table data.', 0.6
        else:
            # If programmatic analysis fails, try VLM as fallback
            return use_vlm_fallback()

    except Exception as e:
        return use_vlm_fallback()

